#!/bin/bash

# ==============================================================================
# Description: Batch call to ArtiMuse model for image aesthetic scoring
# 
# Notes:
# 1. Before running, ensure the ArtiMuse model weights are downloaded and 
#    MODEL_PATH points to the weight directory.
# 2. Please aggregate images generated by GenEval into a single folder as input.
# 3. Important: When generating these images, ensure the "Aesthetic Drawing: " 
#    prefix was added to the prompt.
# ==============================================================================

# --- Path Configuration (Please modify as needed) ---

# Path to model weights (containing config.json, pytorch_model.bin, etc.)
MODEL_PATH="/path/to/your/models/ArtiMuse"

# Folder path for images generated by GenEval
INPUT_IMAGE_DIR="/path/to/your/geneval/results/images"

# JSON file path to save scoring results
OUTPUT_JSON_FILE="./results/aesthetic_scores.json"

# Computational device to use (e.g., cuda, cuda:0, or cpu)
DEVICE="cuda"

# --- Execution ---

echo "[INFO] Starting ArtiMuse aesthetic scoring..."
echo "[INFO] Model Path: $MODEL_PATH"
echo "[INFO] Input Dir:  $INPUT_IMAGE_DIR"
echo "[INFO] Output:     $OUTPUT_JSON_FILE"

# Call Python script
python artimuse_eval.py \
  --model_path "$MODEL_PATH" \
  --input_dir "$INPUT_IMAGE_DIR" \
  --output_file "$OUTPUT_JSON_FILE" \
  --device "$DEVICE"

# Check execution status
if [ $? -eq 0 ]; then
    echo "[INFO] Evaluation finished successfully."
else
    echo "[ERROR] Evaluation failed. Please check the logs."
    exit 1
fi